/**
 * LazyTrex Image Loader
 * Efficiently loads images on demand when they enter the viewport
 * Supports dynamically loaded content (infinite scroll, AJAX, etc.)
 */
const LazyTrexLoader = (function() {
    let imageObserver = null;
    let processedImages = new WeakSet(); // Track processed images to avoid duplicates
    
    /**
     * Loads an image and handles post-load styling
     * @param {HTMLImageElement} image - The image element to load
     */
    function loadImage(image) {
        // Skip if already loaded or has no data-src
        if (!image.dataset.src || image.classList.contains('loaded')) return;
        
        // Set the src and handle onload effects
        const src = image.dataset.src;
        image.src = src;
        
        image.onload = () => {
            // Add loaded class to the image
            image.classList.add('loaded');
            
            // Find and update the blur element if it exists
            const blurElement = image.nextElementSibling;
            if (blurElement?.classList.contains('lazytrex-blur')) {
                blurElement.classList.add('loaded');
            }
            
            // Clean up data attribute to help garbage collection
            delete image.dataset.src;
        };
        
        // Handle load errors
        image.onerror = () => {
            console.warn('LazyTrex: Failed to load image:', src);
            image.classList.add('error');
        };
    }
    
    /**
     * Process new images and add them to the observer
     * @param {NodeList|Array} images - Images to process
     */
    function processImages(images) {
        if (!images.length) return;
        
        // Use Intersection Observer if available (modern browsers)
        if ('IntersectionObserver' in window) {
            // Create observer if it doesn't exist
            if (!imageObserver) {
                imageObserver = new IntersectionObserver(
                    (entries) => {
                        entries.forEach((entry) => {
                            if (entry.isIntersecting) {
                                loadImage(entry.target);
                                imageObserver.unobserve(entry.target);
                            }
                        });
                    },
                    {
                        rootMargin: '50px',
                        threshold: 0.01,
                    }
                );
            }
            
            // Observe new images
            images.forEach((image) => {
                if (!processedImages.has(image)) {
                    imageObserver.observe(image);
                    processedImages.add(image);
                }
            });
        }
        // Fallback for older browsers
        else {
            initFallbackMode();
        }
    }
    
    /**
     * Initialize fallback mode for older browsers
     */
    function initFallbackMode() {
        // Throttle function to limit scroll event firing
        const throttle = (func, limit) => {
            let inThrottle;
            return function () {
                if (!inThrottle) {
                    func.apply(this, arguments);
                    inThrottle = true;
                    setTimeout(() => (inThrottle = false), limit);
                }
            };
        };
        
        /**
         * Checks if an element is in the viewport
         * @param {HTMLElement} element - The element to check
         * @return {boolean} Whether the element is in the viewport
         */
        function isInViewport(element) {
            const rect = element.getBoundingClientRect();
            const offset = 50;
            return (
                rect.top <= window.innerHeight + offset &&
                rect.bottom >= -offset &&
                rect.left <= window.innerWidth &&
                rect.right >= 0
            );
        }
        
        // Process all images in viewport
        const checkImages = () => {
            const images = document.querySelectorAll('.lazytrex-image:not(.loaded)');
            images.forEach((image) => {
                if (isInViewport(image)) {
                    loadImage(image);
                }
            });
        };
        
        // Throttled event handlers
        const throttledCheck = throttle(checkImages, 200);
        
        // Add event listeners (only once)
        if (!window.lazyTrexInitialized) {
            window.addEventListener('scroll', throttledCheck, { passive: true });
            window.addEventListener('resize', throttledCheck, { passive: true });
            window.lazyTrexInitialized = true;
        }
        
        // Initial check for images in viewport
        checkImages();
    }
    
    /**
     * Initialize lazy loading for existing images
     */
    function init() {
        const images = document.querySelectorAll('.lazytrex-image');
        processImages(images);
    }
    
    /**
     * Process new content (call this after adding new content via AJAX/infinite scroll)
     * @param {HTMLElement} container - Optional container to search within
     */
    function refresh(container = document) {
        const images = container.querySelectorAll('.lazytrex-image:not(.loaded)');
        processImages(images);
    }
    
    /**
     * Observe for dynamically added content using MutationObserver
     */
    function observeForNewContent() {
        if ('MutationObserver' in window) {
            const mutationObserver = new MutationObserver((mutations) => {
                mutations.forEach((mutation) => {
                    mutation.addedNodes.forEach((node) => {
                        if (node.nodeType === Node.ELEMENT_NODE) {
                            // Check if the added node itself is a lazy image
                            if (node.classList?.contains('lazytrex-image')) {
                                processImages([node]);
                            }
                            // Check for lazy images within the added node
                            else {
                                const images = node.querySelectorAll?.('.lazytrex-image:not(.loaded)');
                                if (images?.length) {
                                    processImages(images);
                                }
                            }
                        }
                    });
                });
            });
            
            // Start observing
            mutationObserver.observe(document.body, {
                childList: true,
                subtree: true
            });
        }
    }
    
    // Public API
    return {
        init,
        refresh,
        observeForNewContent
    };
})();

// Auto-initialize when the DOM is fully loaded
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
        LazyTrexLoader.init();
        LazyTrexLoader.observeForNewContent(); // Auto-detect new content
    });
} else {
    LazyTrexLoader.init();
    LazyTrexLoader.observeForNewContent(); // Auto-detect new content
}

// Make it globally available for manual calls
window.LazyTrexLoader = LazyTrexLoader;